// AUTO-GENERATED by build.py — do not edit. Source: data/bdls/**
window.BDLS_DATA = {"manifest":{"id":"bdls","title":"BDLS — Basic Disaster Life Support","subtitle":"The Ultimate Course Reviewer","version":"1.0.0","edition":"Based on the NDLSF BDLS v4.0 curriculum","description":"A comprehensive, self-contained study reviewer for Basic Disaster Life Support. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, decision trees, high-yield flashcards, course-style quiz questions, and realistic disaster scenarios. Built around the PRE-DISASTER and DISASTER paradigms, SALT mass-casualty triage, and the all-hazards approach for EMS providers, nurses, physicians, and public-health professionals.","icon":"tornado","color":"#c8102e","accentColor":"#1f6feb","estimatedHours":10,"difficulty":"Beginner to Intermediate","certification":"NDLSF BDLS","examLink":"https://www.ndlsf.org/bdls","audience":["EMT","AEMT","Paramedic","Nurse","Physician","Public Health Professional","Hospital Staff"],"prerequisites":["None — BDLS is an awareness-level course; clinical background helpful"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Disaster Medicine Foundations & the PRE-DISASTER Paradigm","section":"Foundations","difficulty":"Beginner"},{"id":"c02","number":2,"title":"The DISASTER Paradigm","section":"Foundations","difficulty":"Beginner"},{"id":"c03","number":3,"title":"Incident Command & Emergency Management (ICS/NIMS)","section":"Foundations","difficulty":"Intermediate"},{"id":"c04","number":4,"title":"Mass-Casualty Triage: SALT","section":"Response Core","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Natural Disasters","section":"All-Hazards","difficulty":"Beginner"},{"id":"c06","number":6,"title":"Traumatic & Explosive Events","section":"All-Hazards","difficulty":"Intermediate"},{"id":"c07","number":7,"title":"Chemical Events & Decontamination","section":"All-Hazards","difficulty":"Intermediate"},{"id":"c08","number":8,"title":"Biological Events & Pandemics","section":"All-Hazards","difficulty":"Intermediate"},{"id":"c09","number":9,"title":"Nuclear & Radiological Events","section":"All-Hazards","difficulty":"Intermediate"},{"id":"c10","number":10,"title":"Surge Capacity, Psychosocial Care & Vulnerable Populations","section":"Response Core","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Disaster Medicine Foundations & the PRE-DISASTER Paradigm","shortTitle":"Foundations & PRE-DISASTER","estimatedStudyTime":30,"difficulty":"Beginner","learningObjectives":["Define disaster and mass-casualty incident (MCI) from a health-system perspective.","Explain the all-hazards approach and why BDLS teaches a common lexicon.","List the four classic phases of the disaster cycle.","Describe the components of the PRE-DISASTER Paradigm for mitigation and preparedness.","Distinguish disaster response from conventional emergency care priorities.","Describe the health professional's roles before, during, and after a disaster."],"summary":[{"title":"What Makes an Event a Disaster","content":"From the health-system perspective, a disaster is an event in which the needs generated — casualties, destroyed infrastructure, displaced people — exceed the resources immediately available to meet them. The same tornado may be a routine emergency for a large trauma system and a disaster for a rural hospital. A mass-casualty incident (MCI) is an event producing more patients than local resources can manage using routine procedures. The defining feature is the imbalance between needs and resources, not the size of the event itself."},{"title":"The All-Hazards Approach","content":"Rather than writing a separate plan for every possible event, modern disaster medicine uses an all-hazards approach: a common management framework that works across natural disasters, explosions, chemical releases, epidemics, and radiological events, supplemented by hazard-specific annexes. BDLS exists to give all health professionals a shared vocabulary and knowledge base so that physicians, nurses, EMS providers, and public-health workers can integrate smoothly during a response."},{"title":"The Disaster Cycle: Four Phases","content":"Emergency management describes a continuous cycle of four phases. Mitigation: actions that reduce the impact of future events (building codes, flood barriers, immunization programs). Preparedness: planning, training, exercising, and stockpiling before an event. Response: the actions taken during and immediately after the event — the DISASTER Paradigm operates here. Recovery: restoring the community and health system to normal (or improved) function, which can take years. Health professionals have roles in every phase, not only in response."},{"title":"The PRE-DISASTER Paradigm","content":"BDLS frames what should happen before an event with the PRE-DISASTER Paradigm: Planning and practice — realistic, exercised plans at personal, facility, and community levels; Resilience — building the personal, infrastructure, and community capacity to absorb and recover from shocks; Education and training — competency-based learning such as the NDLS course family, so responders share a common playbook. Preparedness done well shrinks the gap between needs and resources when the event arrives."},{"title":"How Disaster Care Differs From Everyday Care","content":"Conventional emergency care applies maximal resources to each individual patient. In a disaster, the goal shifts to achieving the greatest good for the greatest number: triage allocates limited resources, some care is deferred, documentation is abbreviated, and providers may work outside their usual roles under an incident command structure. Recognizing and accepting this shift — before the event — is itself a preparedness skill."},{"title":"Personal and Family Preparedness","content":"A responder whose own family is unprepared is a responder who may not report for duty. Personal preparedness includes a family communication plan, a go-kit with supplies and medications, arrangements for dependents and pets, and knowledge of workplace disaster roles. Health facilities depend on their staff showing up; individual readiness is a system-level asset."}],"clinicalPearls":["A disaster is defined by the needs-versus-resources imbalance, not by the event's size or drama.","The greatest-good-for-the-greatest-number principle governs disaster care and justifies triage decisions that would be unacceptable in daily practice.","Mitigation and preparedness — the quiet phases — save more lives than heroic response.","Your family's preparedness plan is part of your hospital's surge plan: unprepared staff don't show up."],"redFlags":["Facilities that plan for only one hazard instead of using an all-hazards framework.","Plans that exist on paper but have never been exercised.","Responders self-dispatching to a scene without integration into incident command."],"commonMistakes":["Confusing a mass-casualty incident (resource strain) with any large emergency.","Treating disaster response as the only phase that matters and ignoring mitigation, preparedness, and recovery.","Assuming everyday clinical priorities (maximal care per patient) carry over unchanged into disasters."],"memoryAids":["Disaster = Demand > Resources.","The disaster cycle: Mitigate → Prepare → Respond → Recover, then repeat.","PRE-DISASTER: Planning/practice, Resilience, Education — do the work before the sirens."],"decisionTrees":[{"title":"Is This a Disaster (for You)?","content":"Event occurs\n  → Estimate needs: casualties, hazards, infrastructure loss, displaced people\n  → Compare with immediately available resources (staff, space, supplies, systems)\n     → Needs ≤ resources: manage as a conventional (possibly large) emergency\n     → Needs > resources: DISASTER footing\n        → Activate emergency operations / incident command\n        → Shift to greatest-good priorities and formal triage\n        → Request mutual aid and escalate through the system"}],"references":["NDLSF BDLS v4.0 — Disaster Medicine Principles and the PRE-DISASTER Paradigm","NDLSF BDLS v4.0 — All-Hazards Preparedness and the Disaster Cycle"]},"c02":{"id":"c02","title":"The DISASTER Paradigm","shortTitle":"DISASTER Paradigm","estimatedStudyTime":35,"difficulty":"Beginner","learningObjectives":["List the eight components of the DISASTER Paradigm in order.","Describe the detection questions a first-arriving responder must answer.","Explain why establishing incident command early is critical.","Apply safety-and-security thinking to self, scene, and survivors.","Describe hazard assessment, including the risk of secondary events.","Explain the support and triage/treatment components.","Describe evacuation priorities and the transition to recovery."],"summary":[{"title":"One Framework for Every Event","content":"The DISASTER Paradigm is the BDLS all-hazards response framework — a mental checklist that applies whether the event is a flood, a bombing, or an epidemic. Its components are: Detection, Incident command, Safety and security, Assess hazards, Support, Triage and treatment, Evacuation, and Recovery. It gives every responder, from any discipline, the same ordered set of priorities."},{"title":"Detection","content":"Detection asks: does this event exceed available resources — is it a disaster or MCI? Detection can be obvious (an explosion) or insidious (a slowly building epidemic, patients presenting with unusual symptoms across multiple emergency departments). The first-arriving responder estimates the number of casualties, hazards present, and resources needed, and communicates that picture early. Recognizing an event for what it is triggers everything downstream."},{"title":"Incident Command","content":"Someone must be in charge, immediately. The first trained responder on scene establishes incident command and announces it, transferring command later as more senior officers arrive. Incident command creates a single point of coordination, prevents freelancing, and connects the scene to the wider emergency-management system. Health professionals must know how to work inside this structure rather than around it."},{"title":"Safety and Security","content":"The priority order is: yourself, your team, the public/bystanders, then the patients. A responder who becomes a casualty consumes resources rather than adding them. Safety includes appropriate PPE, staging until the scene is cleared, controlling perimeters, and awareness of violence or secondary devices intended to target responders. Security also protects scarce resources — supplies, vehicles, and facilities — from being overwhelmed."},{"title":"Assess Hazards","content":"Actively search for ongoing and secondary hazards: fire, structural collapse, downed power lines, hazardous materials, rising water, aftershocks, and intentional secondary devices timed to strike responders. Hazard assessment is continuous — scenes evolve, and the assessment that was true on arrival may be false an hour later."},{"title":"Support, Triage & Treatment, Evacuation, Recovery","content":"Support: identify what resources — people, supplies, vehicles, facilities, special teams — are needed and request them early, because everything arrives with a delay. Triage and treatment: sort casualties with a standardized method (SALT) and provide the greatest good for the greatest number. Evacuation: move patients to appropriate destinations — distributing them across receiving hospitals rather than overwhelming the nearest one — and consider evacuation of populations at risk. Recovery: begins during the response, restoring systems, supporting responders and survivors, and documenting lessons learned."}],"clinicalPearls":["The DISASTER Paradigm is a checklist you run in order — detection and command come before any patient care.","The nearest hospital is not automatically the right destination; distribute casualties or you simply move the disaster indoors.","Request support early: every resource arrives after a lag, so order for the incident you will have in an hour.","Reassess hazards continuously — secondary devices and evolving scenes target the moment responders relax."],"redFlags":["Rushing to treat the first casualty seen before command, safety, and hazard assessment are addressed.","Multiple EDs seeing clusters of unusual symptoms — a detection signal for a covert biological or chemical event.","All casualties transported to the closest hospital, overwhelming it while others sit idle."],"commonMistakes":["Skipping the announcement of incident command because the scene 'seems manageable.'","Treating safety as a one-time check instead of a continuous process.","Forgetting that recovery planning starts during the response, not after it."],"memoryAids":["D-I-S-A-S-T-E-R: Detection, Incident command, Safety/security, Assess hazards, Support, Triage & treatment, Evacuation, Recovery.","Safety order: me, my team, bystanders, then patients.","Detect → Direct → Protect → Assess → Supply → Sort → Move → Restore."],"decisionTrees":[{"title":"First Responder's DISASTER Sequence","content":"Arrive at possible MCI\n  → DETECTION: needs vs resources — declare MCI/disaster if exceeded\n  → INCIDENT COMMAND: establish and announce (transfer later as needed)\n  → SAFETY & SECURITY: self → team → public → patients; PPE; perimeter\n  → ASSESS HAZARDS: ongoing + secondary (devices, collapse, hazmat); reassess continuously\n  → SUPPORT: request staff, supplies, transport, special teams EARLY\n  → TRIAGE & TREATMENT: SALT; greatest good for greatest number\n  → EVACUATION: right patient, right destination — distribute, don't dump\n  → RECOVERY: begins during response; restore, support, learn"}],"references":["NDLSF BDLS v4.0 — The DISASTER Paradigm","NDLSF BDLS v4.0 — Response Principles and Scene Management"]},"c03":{"id":"c03","title":"Incident Command & Emergency Management (ICS/NIMS)","shortTitle":"ICS / NIMS","estimatedStudyTime":32,"difficulty":"Intermediate","learningObjectives":["Describe the purpose and core features of the Incident Command System (ICS).","Name the five major ICS functional sections and their responsibilities.","Explain span of control and modular expansion.","Define unified command and when it is used.","Describe NIMS and how it standardizes response across agencies.","Explain the hospital's version of ICS and the health professional's place in it."],"summary":[{"title":"Why Incident Command Exists","content":"Large events involve many agencies — fire, EMS, police, public works, hospitals, public health — that must act as one organization. The Incident Command System (ICS) is a standardized, scalable management structure that provides common terminology, clear chain of command, defined roles, and integrated communications. It prevents the classic failure of disasters: multiple groups working hard at cross purposes."},{"title":"The Five Functional Sections","content":"ICS organizes work into five functions. Command sets objectives and holds overall authority; it includes the command staff — safety officer, public information officer, and liaison officer. Operations does the tactical work: rescue, triage, treatment, transport. Planning collects information, tracks resources, and writes the incident action plan. Logistics obtains everything the response needs — supplies, facilities, food, communications. Finance/Administration tracks costs, contracts, claims, and time records. Every task in a response lives somewhere in these five functions."},{"title":"Modular, Scalable, Span of Control","content":"ICS expands and contracts with the incident: a small event may need only an incident commander, while a catastrophe activates every section with branches, divisions, and groups. The guiding rule is span of control: one supervisor should directly manage roughly three to seven people (five is the classic optimum). When a supervisor's span grows too large, the structure subdivides."},{"title":"Unified Command and Transfer of Command","content":"When an incident crosses jurisdictions or disciplines — a hazmat spill involving fire, police, EMS, and environmental agencies — unified command lets the key agencies share command decisions while maintaining a single coordinated plan and one Operations section. Command transfers formally, with a briefing, when a more qualified or designated officer assumes it; everyone is told who now commands."},{"title":"NIMS: The National Framework","content":"The National Incident Management System (NIMS) is the U.S. doctrine that standardizes incident management across all levels of government and the private sector. It incorporates ICS, defines resource typing (so a requested 'strike team' means the same thing everywhere), credentialing, mutual aid, and emergency operations centers (EOCs) that support on-scene command. For health professionals, NIMS means your hospital's system plugs into the same structure the fire service uses."},{"title":"Hospital Incident Command (HICS)","content":"Hospitals use an ICS adaptation (commonly the Hospital Incident Command System, HICS) with the same five functions applied to facility problems: bed surge, staff callback, supply shortages, evacuation. Clinicians in a disaster work within assigned roles — often defined by job action sheets — reporting through the structure rather than to their everyday supervisors. Knowing your facility's command structure before the event is a core BDLS competency."}],"clinicalPearls":["In ICS you report to your incident supervisor, not your everyday boss — one person, one supervisor.","Span of control 3–7 (optimally ~5): when a leader has more direct reports than that, the structure should subdivide.","The safety officer can halt any operation immediately — the one role with that authority besides command.","Job action sheets convert your clinical skills into a defined incident role; read yours before the disaster."],"redFlags":["Multiple agencies each running their own separate command posts for the same incident.","A supervisor directly managing 15 people — span of control has collapsed.","Staff bypassing the command structure to act on hallway instructions."],"commonMistakes":["Confusing the incident commander (on-scene authority) with the EOC (off-scene support and coordination).","Assuming ICS is only for fire services — it is designed for all disciplines including hospitals.","Forgetting the formal briefing when command transfers."],"memoryAids":["Five functions — C-O-P-L-F: Command, Operations, Planning, Logistics, Finance/Admin.","'Command thinks, Operations does, Planning tracks, Logistics gets, Finance pays.'","Span of control: one hand — about five fingers, about five reports."],"decisionTrees":[{"title":"Fitting Into Incident Command as a Health Professional","content":"Disaster activation announced\n  → Report to your designated check-in point (never self-dispatch)\n  → Receive assignment + job action sheet\n  → Identify YOUR incident supervisor (one person)\n  → Perform assigned role; communicate up the chain\n     → Task outside your competence? Say so — constructive refusal is safety\n     → New hazard or resource need? Report to your supervisor\n  → At shift end: formal handoff + demobilization through the system"}],"references":["NDLSF BDLS v4.0 — Incident Command and Emergency Management Systems","FEMA — NIMS and ICS doctrine (as taught in BDLS v4.0)"]},"c04":{"id":"c04","title":"Mass-Casualty Triage: SALT","shortTitle":"SALT Triage","estimatedStudyTime":40,"difficulty":"Intermediate","learningObjectives":["Explain the purpose of mass-casualty triage and how it differs from everyday triage.","Describe the SALT acronym and the global sorting step.","List the rapid lifesaving interventions permitted during SALT triage.","Assign casualties to the five SALT categories using the assessment questions.","Explain the expectant category and when it is used.","Describe re-triage and the dynamic nature of triage decisions."],"summary":[{"title":"Why a Standardized Triage Method","content":"When casualties outnumber resources, providers must decide who is treated and transported first. SALT — Sort, Assess, Lifesaving interventions, Treatment and/or transport — is the CDC-sponsored national standard taught in BDLS, designed so that responders from any agency triage the same way. Unlike daily triage (which finds the sickest patient for maximal care), mass-casualty triage rations care to produce the most survivors overall."},{"title":"Step 1 — Sort: Global Sorting by Voice and Movement","content":"SALT begins with a global sort of the whole scene using two commands. First: 'If you can hear me and need help, walk to this area' — those who walk are assessed last (lowest priority for individual assessment, often Minimal). Second, to those remaining: 'Wave your arm or move so we can find you' — those who wave or make purposeful movements are assessed second. Casualties who are still, or with obvious life threats such as massive bleeding, are assessed first. Sorting prioritizes individual assessment without touching anyone yet."},{"title":"Step 2/3 — Assess with Lifesaving Interventions","content":"Each casualty gets a rapid individual assessment combined with only those lifesaving interventions that take seconds: control massive hemorrhage (tourniquet or direct pressure), open the airway with positioning (for a child, consider giving two rescue breaths), chest decompression for tension pneumothorax (trained providers), and auto-injector antidotes (such as for nerve agents). These are done immediately, during triage, before assigning a category — and the triage officer then moves on rather than staying to treat."},{"title":"Assigning Categories: The Assessment Questions","content":"After lifesaving interventions, ask in sequence: Is the casualty breathing? If not (adult) — Dead. Does the casualty obey commands or make purposeful movements? Is there a peripheral pulse? Are they not in respiratory distress? Is major hemorrhage controlled? If ALL yes: the casualty is Minimal if the injuries are minor, otherwise Delayed. If ANY no: the casualty is Immediate — unless the injuries are so severe that survival is unlikely given the resources currently available, in which case Expectant."},{"title":"The Five SALT Categories","content":"Immediate (red): life-threatening injuries, likely to survive with prompt care — first priority for treatment and transport. Delayed (yellow): significant injuries, but care can wait without immediate threat to life. Minimal (green): walking wounded with minor injuries. Expectant (gray): alive, but survival unlikely with the resources currently available — receives comfort care and is re-triaged if resources improve. Dead (black): not breathing after airway opening. The expectant category exists precisely because resources are limited; it is a resource decision, not an abandonment."},{"title":"Triage Is Dynamic","content":"Triage decisions are made with incomplete information and changing resources, so they must be repeated: at the scene, at the treatment area, before transport, and on hospital arrival. A Delayed patient can deteriorate to Immediate; an Expectant patient can be upgraded when more resources arrive. Triage tags or visible markings communicate categories, and re-triage keeps them honest."}],"clinicalPearls":["SALT's global sort triages the crowd before you touch a single patient — voice commands do the first pass for you.","Lifesaving interventions during triage are limited to seconds-long actions: hemorrhage control, airway positioning (± 2 breaths for a child), chest decompression, auto-injector antidotes.","An apneic adult after airway opening is Dead in SALT; a child gets consideration of two rescue breaths first — consistent with the hypoxic nature of pediatric arrest.","Expectant is not Dead: comfort care always, and re-triage when resources improve."],"redFlags":["The triage officer stopping to provide prolonged care — triage halts and the scene backs up.","Ignoring the quiet, still casualties while treating the loudest ones.","Never re-triaging: categories assigned in the first 10 minutes silently become wrong."],"commonMistakes":["Treating walking wounded as 'fine' — they are assessed last, but they still get assessed.","Confusing Expectant (gray, alive) with Dead (black).","Spending minutes on CPR during mass-casualty triage — resource-intensive care for one apneic casualty costs many salvageable lives."],"memoryAids":["SALT: Sort, Assess, Lifesaving interventions, Treatment/transport.","Sort commands: 'Walk' → assess third; 'Wave' → assess second; Still/obvious threat → assess first.","Categories: Red now, Yellow later, Green walks, Gray waits with comfort, Black is gone."],"decisionTrees":[{"title":"SALT Individual Assessment","content":"Casualty (after global sort)\n  → Lifesaving interventions as needed (seconds only):\n     bleeding control | airway positioning (child: consider 2 breaths) | chest decompression | auto-injector\n  → Breathing?\n     → No (adult): DEAD (black)\n     → No (child, after breaths): DEAD\n     → Yes:\n        → Obeys commands / purposeful movement?\n        → Peripheral pulse present?\n        → No respiratory distress?\n        → Major hemorrhage controlled?\n           → ALL yes + minor injuries only: MINIMAL (green)\n           → ALL yes + significant injuries: DELAYED (yellow)\n           → ANY no + likely to survive with current resources: IMMEDIATE (red)\n           → ANY no + survival unlikely with current resources: EXPECTANT (gray)\n  → Tag, move on, and RE-TRIAGE at every stage"}],"references":["NDLSF BDLS v4.0 — Mass-Casualty Triage and SALT","CDC-sponsored SALT Mass Casualty Triage consensus guideline"]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What defines a disaster from the health-system perspective?","answer":"An event whose needs (casualties, hazards, infrastructure loss) exceed the resources immediately available to meet them — an imbalance, not a size threshold.","category":"Definitions"},{"id":"c01_fc02","question":"What is a mass-casualty incident (MCI)?","answer":"An event producing more patients than local resources can manage using routine procedures.","category":"Definitions"},{"id":"c01_fc03","question":"What is the all-hazards approach?","answer":"One common management framework that works across all disaster types (natural, explosive, chemical, biological, radiological), supplemented by hazard-specific annexes.","category":"Concepts"},{"id":"c01_fc04","question":"List the four phases of the disaster cycle.","answer":"Mitigation, Preparedness, Response, Recovery — a continuous cycle.","category":"Disaster Cycle"},{"id":"c01_fc05","question":"Give an example of mitigation.","answer":"Actions that reduce future impact: enforcing building codes, flood barriers, immunization programs.","category":"Disaster Cycle"},{"id":"c01_fc06","question":"What does the PRE-DISASTER Paradigm cover?","answer":"Pre-event readiness: Planning and practice, Resilience, and Education and training.","category":"PRE-DISASTER"},{"id":"c01_fc07","question":"What is the guiding ethical principle of disaster care?","answer":"The greatest good for the greatest number — allocating limited resources to benefit the most patients, unlike maximal individual care in daily practice.","category":"Concepts"},{"id":"c01_fc08","question":"Why does BDLS emphasize a common lexicon?","answer":"So physicians, nurses, EMS, and public-health workers from different agencies can integrate smoothly with shared vocabulary and expectations during a response.","category":"Concepts"},{"id":"c01_fc09","question":"Why is personal/family preparedness a system-level issue?","answer":"Staff with unprepared families may not report for duty; facility surge capacity depends on staff availability.","category":"Preparedness"},{"id":"c01_fc10","question":"What belongs in a responder's personal preparedness?","answer":"Family communication plan, go-kit with supplies and medications, arrangements for dependents and pets, and knowledge of workplace disaster roles.","category":"Preparedness"},{"id":"c01_fc11","question":"In which disaster phase does the DISASTER Paradigm operate?","answer":"The response phase — during and immediately after the event.","category":"Disaster Cycle"},{"id":"c01_fc12","question":"What is resilience in the PRE-DISASTER context?","answer":"The capacity of individuals, infrastructure, and communities to absorb a shock and recover from it.","category":"PRE-DISASTER"},{"id":"c01_fc13","question":"Why can the same event be a disaster in one place and not another?","answer":"Because the definition depends on local resources: a rural hospital may be overwhelmed by casualties a large trauma system absorbs routinely.","category":"Definitions"},{"id":"c01_fc14","question":"How does documentation change in disaster care?","answer":"It is abbreviated (e.g., triage tags) so that scarce provider time goes to patient care.","category":"Concepts"},{"id":"c01_fc15","question":"What is the danger of an unexercised disaster plan?","answer":"Plans that were never practiced fail under stress — exercising reveals gaps and builds the muscle memory the response phase requires.","category":"Preparedness"}]},"c02":{"chapter":"c02","cards":[{"id":"c02_fc01","question":"What does the DISASTER mnemonic stand for?","answer":"Detection, Incident command, Safety and security, Assess hazards, Support, Triage and treatment, Evacuation, Recovery.","category":"Framework"},{"id":"c02_fc02","question":"What question does the Detection step answer?","answer":"Do the needs of this event exceed the available resources — is this a disaster/MCI?","category":"Detection"},{"id":"c02_fc03","question":"Give an example of insidious (non-obvious) detection.","answer":"A covert biological event detected only as clusters of unusual symptoms across multiple emergency departments.","category":"Detection"},{"id":"c02_fc04","question":"Who establishes incident command initially?","answer":"The first trained responder on scene — command is announced and later transferred as more senior officers arrive.","category":"Incident Command"},{"id":"c02_fc05","question":"What is the safety priority order at a disaster scene?","answer":"Yourself first, then your team, then the public/bystanders, then the patients.","category":"Safety"},{"id":"c02_fc06","question":"Why does responder safety come before patient care?","answer":"An injured responder stops adding resources and starts consuming them, worsening the needs-resources gap.","category":"Safety"},{"id":"c02_fc07","question":"What are secondary devices?","answer":"Explosives or hazards deliberately timed/placed to injure responders after the initial event — a key reason hazard assessment is continuous.","category":"Hazards"},{"id":"c02_fc08","question":"Why must support be requested early?","answer":"Every resource arrives with a delay, so requests should anticipate the incident's needs an hour ahead, not its needs right now.","category":"Support"},{"id":"c02_fc09","question":"What triage method does BDLS teach for the Triage & treatment step?","answer":"SALT — Sort, Assess, Lifesaving interventions, Treatment and/or transport.","category":"Triage"},{"id":"c02_fc10","question":"What is the key principle of disaster evacuation/transport?","answer":"Distribute casualties across appropriate receiving facilities — sending everyone to the nearest hospital just relocates the disaster.","category":"Evacuation"},{"id":"c02_fc11","question":"When does recovery begin?","answer":"During the response — restoring systems, supporting responders and survivors, and capturing lessons learned start before the scene is closed.","category":"Recovery"},{"id":"c02_fc12","question":"What should the first radio report from a scene include?","answer":"The detection picture: estimated casualties, hazards present, resources needed, and that command is established.","category":"Detection"},{"id":"c02_fc13","question":"Why is 'freelancing' dangerous at a disaster scene?","answer":"Responders acting outside incident command break accountability, duplicate work, and endanger themselves and the operation.","category":"Incident Command"},{"id":"c02_fc14","question":"Name hazards to actively reassess during a response.","answer":"Fire, structural collapse, downed lines, hazmat, rising water, aftershocks, violence, and secondary devices.","category":"Hazards"},{"id":"c02_fc15","question":"Why is the DISASTER Paradigm called 'all-hazards'?","answer":"The same ordered checklist applies to any event type — flood, bombing, epidemic — giving all responders shared priorities.","category":"Framework"}]},"c03":{"chapter":"c03","cards":[{"id":"c03_fc01","question":"What is the Incident Command System (ICS)?","answer":"A standardized, scalable management structure providing common terminology, clear chain of command, defined roles, and integrated communications for any incident.","category":"ICS Basics"},{"id":"c03_fc02","question":"Name the five ICS functional sections.","answer":"Command, Operations, Planning, Logistics, and Finance/Administration.","category":"ICS Structure"},{"id":"c03_fc03","question":"What does the Operations section do?","answer":"The tactical work of the response: rescue, triage, treatment, and transport.","category":"ICS Structure"},{"id":"c03_fc04","question":"What does the Planning section do?","answer":"Collects and evaluates information, tracks resources, and prepares the incident action plan.","category":"ICS Structure"},{"id":"c03_fc05","question":"What does the Logistics section do?","answer":"Obtains everything the response needs — supplies, facilities, communications, food, and medical support for responders.","category":"ICS Structure"},{"id":"c03_fc06","question":"What does Finance/Administration handle?","answer":"Cost tracking, contracts and procurement, compensation/claims, and time records.","category":"ICS Structure"},{"id":"c03_fc07","question":"Who makes up the command staff?","answer":"The safety officer, public information officer, and liaison officer, working directly for the incident commander.","category":"ICS Structure"},{"id":"c03_fc08","question":"What unique authority does the safety officer hold?","answer":"The authority to immediately stop any operation that poses imminent danger.","category":"Safety"},{"id":"c03_fc09","question":"What is span of control in ICS?","answer":"One supervisor should directly manage about 3–7 people (classically 5); beyond that, the structure subdivides.","category":"ICS Principles"},{"id":"c03_fc10","question":"What is unified command?","answer":"A shared command arrangement in which key agencies/jurisdictions jointly set objectives under one coordinated plan with a single Operations section.","category":"ICS Principles"},{"id":"c03_fc11","question":"What is NIMS?","answer":"The National Incident Management System — the U.S. doctrine standardizing incident management (ICS, resource typing, credentialing, mutual aid, EOCs) across agencies and levels of government.","category":"NIMS"},{"id":"c03_fc12","question":"How does a hospital use incident command?","answer":"Through an ICS adaptation (e.g., HICS) applying the same five functions to facility problems — surge, staffing, supplies, evacuation — with roles defined by job action sheets.","category":"Hospital ICS"},{"id":"c03_fc13","question":"In ICS, who do you take direction from?","answer":"Your single assigned incident supervisor — not your everyday manager (unity of command).","category":"ICS Principles"},{"id":"c03_fc14","question":"How is command transferred?","answer":"Formally, with a briefing of the incoming commander, and an announcement so everyone knows who now commands.","category":"ICS Principles"},{"id":"c03_fc15","question":"What is the role of an Emergency Operations Center (EOC)?","answer":"Off-scene coordination and support — resources, information, policy — supporting (not replacing) on-scene incident command.","category":"NIMS"}]},"c04":{"chapter":"c04","cards":[{"id":"c04_fc01","question":"What does SALT stand for?","answer":"Sort, Assess, Lifesaving interventions, Treatment and/or transport — the CDC-sponsored national mass-casualty triage standard.","category":"Framework"},{"id":"c04_fc02","question":"What are the two global sorting commands?","answer":"1) 'If you can hear me and need help, walk to this area' (walkers assessed last). 2) 'Wave your arm or move' (wavers assessed second). Still casualties or obvious life threats are assessed first.","category":"Sort"},{"id":"c04_fc03","question":"List the rapid lifesaving interventions permitted during SALT triage.","answer":"Control massive hemorrhage, open the airway by positioning (child: consider 2 rescue breaths), chest decompression for tension pneumothorax (trained providers), and auto-injector antidotes.","category":"Lifesaving Interventions"},{"id":"c04_fc04","question":"Name the five SALT triage categories with colors.","answer":"Immediate (red), Delayed (yellow), Minimal (green), Expectant (gray), Dead (black).","category":"Categories"},{"id":"c04_fc05","question":"What are the SALT assessment questions after lifesaving interventions?","answer":"Breathing? Obeys commands/purposeful movement? Peripheral pulse? No respiratory distress? Major hemorrhage controlled?","category":"Assess"},{"id":"c04_fc06","question":"An adult remains apneic after airway opening during SALT. Category?","answer":"Dead (black). CPR is not performed during mass-casualty triage of an apneic adult.","category":"Categories"},{"id":"c04_fc07","question":"How does SALT treat an apneic child differently from an adult?","answer":"For a child, consider giving two rescue breaths after opening the airway; if breathing does not resume, the child is Dead. This reflects the hypoxic nature of pediatric arrest.","category":"Pediatric"},{"id":"c04_fc08","question":"What does the Expectant (gray) category mean?","answer":"Alive, but survival is unlikely with the resources CURRENTLY available. Comfort care is provided, and the patient is re-triaged if resources improve — it is not the same as Dead.","category":"Categories"},{"id":"c04_fc09","question":"A casualty answers all assessment questions 'yes' and has only minor injuries. Category?","answer":"Minimal (green).","category":"Categories"},{"id":"c04_fc10","question":"A casualty answers all questions 'yes' but has significant injuries. Category?","answer":"Delayed (yellow) — significant care needed, but it can wait.","category":"Categories"},{"id":"c04_fc11","question":"A casualty fails one assessment question but is salvageable with current resources. Category?","answer":"Immediate (red) — first priority for treatment and transport.","category":"Categories"},{"id":"c04_fc12","question":"Why must triage be repeated (re-triage)?","answer":"Patients deteriorate or improve and resources change; categories are reassessed at the scene, treatment area, transport, and hospital arrival.","category":"Dynamics"},{"id":"c04_fc13","question":"How is everyday triage different from mass-casualty triage?","answer":"Everyday triage finds the sickest patient for maximal individual care; mass-casualty triage rations limited resources to produce the most survivors overall.","category":"Concepts"},{"id":"c04_fc14","question":"Why doesn't the triage officer stop to treat patients?","answer":"Beyond seconds-long lifesaving interventions, stopping halts triage for everyone still unsorted — the officer tags and moves on.","category":"Concepts"},{"id":"c04_fc15","question":"Are the walking wounded 'cleared' by walking?","answer":"No — walking assigns them the last assessment priority, but every casualty still receives individual assessment; injuries hide in the green group.","category":"Sort"},{"id":"c04_fc16","question":"What tools communicate triage categories on scene?","answer":"Triage tags, colored tape/tarps, or other visible markings, updated at each re-triage.","category":"Dynamics"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"Which statement best defines a disaster from a health-system perspective?","options":["A. Any event involving more than 100 casualties","B. An event in which needs exceed the immediately available resources","C. Any weather-related emergency","D. An event declared by the federal government"],"correct":1,"rationale":"The health-system definition centers on the imbalance between needs and resources. Casualty counts, weather, or declarations do not define it — a small event can be a disaster where resources are scarce.","difficulty":"Easy"},{"id":"c01_q02","question":"What is the correct order of the four phases of the disaster cycle?","options":["A. Response, Recovery, Mitigation, Preparedness","B. Mitigation, Preparedness, Response, Recovery","C. Preparedness, Mitigation, Recovery, Response","D. Detection, Response, Recovery, Review"],"correct":1,"rationale":"The classic cycle runs Mitigation → Preparedness → Response → Recovery, then feeds back into mitigation for the next event.","difficulty":"Easy"},{"id":"c01_q03","question":"Installing flood barriers and enforcing seismic building codes are examples of which phase?","options":["A. Response","B. Recovery","C. Mitigation","D. Triage"],"correct":2,"rationale":"Mitigation comprises actions taken to reduce the impact of future events — structural and policy measures like barriers and building codes.","difficulty":"Easy"},{"id":"c01_q04","question":"The PRE-DISASTER Paradigm emphasizes which pre-event elements?","options":["A. Planning and practice, resilience, and education and training","B. Triage, treatment, and transport","C. Detection and evacuation","D. Response and recovery only"],"correct":0,"rationale":"PRE-DISASTER frames readiness before an event: exercised plans, resilient people and infrastructure, and competency-based education such as the NDLS courses.","difficulty":"Medium"},{"id":"c01_q05","question":"How do care priorities change in a disaster compared with daily emergency care?","options":["A. They do not change","B. From maximal care for each individual to the greatest good for the greatest number","C. From triage to first-come, first-served","D. All patients receive identical care"],"correct":1,"rationale":"Disaster care allocates limited resources to benefit the most patients. Triage, deferred care, and abbreviated documentation follow from this shift.","difficulty":"Easy"},{"id":"c01_q06","question":"Why does the same tornado count as a disaster for a rural hospital but not for a metropolitan trauma system?","options":["A. Because tornado severity varies by region","B. Because the definition depends on the balance between needs and locally available resources","C. Because rural hospitals use different triage colors","D. Because federal declarations differ"],"correct":1,"rationale":"Disaster is relative to resources: casualties that overwhelm a small facility may be absorbed routinely by a large system.","difficulty":"Medium"},{"id":"c01_q07","question":"What is the purpose of the all-hazards approach?","options":["A. To write a unique plan for every conceivable event","B. To use one common management framework across all disaster types, with hazard-specific annexes","C. To focus planning only on the most likely hazard","D. To eliminate the need for training"],"correct":1,"rationale":"All-hazards planning builds one flexible framework that applies to natural, explosive, chemical, biological, and radiological events, supplemented by specific annexes — more robust and efficient than separate plans.","difficulty":"Medium"},{"id":"c01_q08","question":"A hospital's disaster plan is thorough but has never been exercised. What is the main risk?","options":["A. None — a written plan is sufficient","B. The plan will fail under stress because gaps were never revealed and staff lack practiced roles","C. The plan will expire legally","D. Exercises are only for EMS agencies"],"correct":1,"rationale":"Exercising is what converts paper plans into performance: it exposes gaps, builds familiarity, and creates the muscle memory needed during a real response.","difficulty":"Easy"},{"id":"c01_q09","question":"Which is a component of a responder's personal preparedness?","options":["A. A family communication plan and go-kit","B. Memorizing every federal regulation","C. Owning specialized rescue vehicles","D. Avoiding disaster training to stay flexible"],"correct":0,"rationale":"Personal preparedness — communication plan, go-kit, dependent care arrangements, knowledge of workplace roles — keeps responders able to report for duty.","difficulty":"Easy"},{"id":"c01_q10","question":"Why is staff personal preparedness a facility-level concern?","options":["A. It is not — it is purely private","B. Surge capacity depends on staff reporting for duty, and staff with unprepared families often cannot","C. It reduces insurance premiums","D. It replaces the need for a hospital plan"],"correct":1,"rationale":"A hospital's surge plan assumes staff availability. Personal and family readiness directly affects whether the workforce shows up in a crisis.","difficulty":"Medium"},{"id":"c01_q11","question":"A mass-casualty incident (MCI) is best defined as:","options":["A. Any incident with fatalities","B. An event producing more patients than local resources can manage using routine procedures","C. An incident involving hazardous materials","D. Any incident requiring more than one ambulance"],"correct":1,"rationale":"The MCI definition parallels the disaster definition: patient load beyond what routine local procedures can handle.","difficulty":"Easy"},{"id":"c01_q12","question":"During a disaster response, a provider is asked to work in a role outside their usual daily assignment, under incident command. This is:","options":["A. A violation of disaster principles","B. An expected feature of disaster response within the command structure","C. Only allowed for physicians","D. Evidence of a failed plan"],"correct":1,"rationale":"Disasters routinely require flexible role assignment under incident command; preparing providers for this shift is part of BDLS training.","difficulty":"Medium"},{"id":"c01_q13","question":"Which activity belongs to the RECOVERY phase?","options":["A. Field triage of casualties","B. Restoring health-system function and community services after the event, potentially over years","C. Stockpiling supplies before an event","D. Building levees"],"correct":1,"rationale":"Recovery restores the community and health system to normal or improved function. Triage is response; stockpiling is preparedness; levees are mitigation.","difficulty":"Medium"},{"id":"c01_q14","question":"Immunization campaigns that reduce a community's vulnerability to epidemics are an example of:","options":["A. Response","B. Mitigation","C. Triage","D. Evacuation"],"correct":1,"rationale":"Reducing the future impact of a hazard — including biological hazards — is mitigation.","difficulty":"Hard"},{"id":"c01_q15","question":"Health professionals converging on a disaster scene without being requested or integrated into incident command are:","options":["A. Always helpful","B. A known hazard — self-dispatched responders complicate scene management and safety","C. Required by law","D. The preferred staffing method"],"correct":1,"rationale":"Spontaneous, unintegrated responders burden scene safety, accountability, and coordination. Responding through the system — when requested, into an assigned role — is the professional standard.","difficulty":"Medium"},{"id":"c01_q16","question":"Which best captures why mitigation and preparedness 'save more lives than response'?","options":["A. Response is unimportant","B. Pre-event actions shrink the needs-versus-resources gap before it opens, preventing casualties that no response could later recover","C. Responders are usually unavailable","D. It is a slogan without basis"],"correct":1,"rationale":"Codes that keep buildings standing, plans that speed evacuation, and trained staff prevent deaths outright; even a perfect response can only salvage what the event has already done.","difficulty":"Hard"}]},"c02":{"chapter":"c02","questions":[{"id":"c02_q01","question":"What does the 'D' in the DISASTER Paradigm stand for?","options":["A. Decontamination","B. Detection","C. Defibrillation","D. Documentation"],"correct":1,"rationale":"The paradigm begins with Detection — recognizing that an event's needs exceed available resources.","difficulty":"Easy"},{"id":"c02_q02","question":"Which is the correct order of the DISASTER Paradigm components?","options":["A. Triage, Detection, Safety, Command, Support, Hazards, Evacuation, Recovery","B. Detection, Incident command, Safety and security, Assess hazards, Support, Triage and treatment, Evacuation, Recovery","C. Detection, Safety, Triage, Command, Hazards, Support, Recovery, Evacuation","D. Incident command, Detection, Triage, Evacuation, Safety, Support, Hazards, Recovery"],"correct":1,"rationale":"The ordered checklist is Detection → Incident command → Safety and security → Assess hazards → Support → Triage and treatment → Evacuation → Recovery.","difficulty":"Easy"},{"id":"c02_q03","question":"You are the first trained responder at a building collapse with many casualties. After sizing up the scene, what comes next?","options":["A. Begin treating the nearest casualty","B. Establish and announce incident command","C. Start evacuating patients to the closest hospital","D. Wait for a supervisor before doing anything"],"correct":1,"rationale":"After detection, the first trained responder establishes incident command, creating a coordination point; command transfers later as senior officers arrive. Patient care before command and safety leads to chaos.","difficulty":"Medium"},{"id":"c02_q04","question":"What is the correct safety priority order at a disaster scene?","options":["A. Patients, bystanders, team, self","B. Self, team, public/bystanders, patients","C. Team, patients, self, public","D. There is no priority order"],"correct":1,"rationale":"Protect yourself first, then your team, then the public, then patients — an injured rescuer consumes resources instead of providing them.","difficulty":"Easy"},{"id":"c02_q05","question":"At a bombing scene, hazard assessment must specifically consider:","options":["A. Only the original blast site","B. Secondary devices deliberately targeting responders","C. Weather forecasts for next week","D. Hospital bed counts"],"correct":1,"rationale":"Intentional events may include secondary devices timed to strike responders — a core reason hazard assessment is continuous and staging discipline matters.","difficulty":"Medium"},{"id":"c02_q06","question":"Why should resource support be requested early in an incident?","options":["A. To impress command","B. Because resources arrive with a delay — order for the incident you will have, not the one you see","C. Because requests expire","D. It should actually be requested last"],"correct":1,"rationale":"Mutual aid, supplies, and transport all take time to arrive. Anticipatory requests keep resources flowing in phase with the incident's growth.","difficulty":"Medium"},{"id":"c02_q07","question":"Which transport decision best reflects disaster evacuation principles?","options":["A. Send all 40 casualties to the nearest hospital","B. Distribute casualties by severity across multiple appropriate receiving facilities","C. Transport only the walking wounded","D. Hold all patients on scene until every one is fully stabilized"],"correct":1,"rationale":"Dumping every casualty on the closest hospital recreates the disaster inside it. Command distributes patients by acuity and capability across the system.","difficulty":"Medium"},{"id":"c02_q08","question":"Clusters of patients with similar unusual symptoms appearing at several EDs across a city over two days most likely represents:","options":["A. Coincidence requiring no action","B. The detection phase of an insidious (possibly biological/chemical) event","C. A staffing problem","D. Normal seasonal variation always"],"correct":1,"rationale":"Covert releases and epidemics announce themselves as syndromic clusters. Recognizing them as a detection signal — and notifying public health — triggers the response system.","difficulty":"Hard"},{"id":"c02_q09","question":"A physician bypasses the incident command post and begins directing ambulances personally. This behavior is:","options":["A. Ideal physician leadership","B. Freelancing — it breaks unified coordination and accountability","C. Required by medical ethics","D. The definition of unified command"],"correct":1,"rationale":"Acting outside the command structure (freelancing) fragments the operation, duplicates or contradicts orders, and endangers the responder. Clinical skills are contributed inside assigned roles.","difficulty":"Medium"},{"id":"c02_q10","question":"When should recovery activities begin?","options":["A. Only after the scene is fully closed","B. During the response itself","C. One year after the event","D. Never — recovery is not a responder concern"],"correct":1,"rationale":"Recovery starts during response: restoring systems, tracking patients, supporting responders and survivors, and documenting lessons learned.","difficulty":"Easy"},{"id":"c02_q11","question":"The first radio report from the initial responder at an MCI should communicate:","options":["A. A complete list of patient names","B. Estimated casualty count, hazards, resources needed, and that command is established","C. Only the responder's unit number","D. The names of the deceased"],"correct":1,"rationale":"The early size-up report paints the detection picture and mobilizes the system: casualties, hazards, needs, and command status.","difficulty":"Medium"},{"id":"c02_q12","question":"Which action violates the Safety and security component?","options":["A. Staging until the scene is declared safe","B. Entering an unstable collapsed structure alone to reach a casualty faster","C. Wearing appropriate PPE","D. Establishing a perimeter"],"correct":1,"rationale":"Entering an uncleared, unstable structure alone risks converting a rescuer into a casualty — the exact failure the safety hierarchy exists to prevent.","difficulty":"Easy"},{"id":"c02_q13","question":"In the DISASTER Paradigm, triage and treatment are performed using:","options":["A. First-come, first-served order","B. A standardized method (SALT) serving the greatest good for the greatest number","C. Alphabetical order","D. Insurance status"],"correct":1,"rationale":"BDLS teaches SALT, the CDC-sponsored national standard, to sort casualties so limited resources produce the most total benefit.","difficulty":"Easy"},{"id":"c02_q14","question":"Why is hazard assessment described as continuous rather than one-time?","options":["A. To create paperwork","B. Scenes evolve — collapse, fire spread, aftershocks, or secondary devices can appear after arrival","C. Because the first assessment is always wrong","D. It is actually one-time"],"correct":1,"rationale":"The hazard picture changes: what was safe on arrival may become lethal. Continuous reassessment protects responders throughout the operation.","difficulty":"Medium"},{"id":"c02_q15","question":"Which pairing of paradigm component and action is correct?","options":["A. Support — establishing a perimeter","B. Evacuation — distributing patients to appropriate facilities","C. Detection — providing definitive care","D. Recovery — initial scene size-up"],"correct":1,"rationale":"Evacuation covers moving the right patient to the right destination. Perimeters are safety/security; size-up is detection; definitive care follows triage/treatment.","difficulty":"Medium"},{"id":"c02_q16","question":"The DISASTER Paradigm applies to which events?","options":["A. Only explosions","B. Only natural disasters","C. All hazards — floods, bombings, epidemics, chemical and radiological events alike","D. Only declared federal disasters"],"correct":2,"rationale":"The paradigm is BDLS's all-hazards checklist: the same ordered priorities regardless of the event's cause.","difficulty":"Easy"}]},"c03":{"chapter":"c03","questions":[{"id":"c03_q01","question":"Which are the five major functional sections of ICS?","options":["A. Command, Operations, Planning, Logistics, Finance/Administration","B. Triage, Treatment, Transport, Staging, Morgue","C. Police, Fire, EMS, Hospital, Public Health","D. Detection, Safety, Support, Evacuation, Recovery"],"correct":0,"rationale":"ICS organizes all incident work into Command, Operations, Planning, Logistics, and Finance/Administration.","difficulty":"Easy"},{"id":"c03_q02","question":"Field triage, treatment, and transport belong to which ICS section?","options":["A. Planning","B. Operations","C. Logistics","D. Finance/Administration"],"correct":1,"rationale":"Operations performs the tactical, hands-on work of the response, including all patient-care activities.","difficulty":"Easy"},{"id":"c03_q03","question":"Obtaining ventilators, food for responders, and portable radios is the job of:","options":["A. Command","B. Operations","C. Logistics","D. Planning"],"correct":2,"rationale":"Logistics acquires the resources the response needs — supplies, facilities, communications, and responder support.","difficulty":"Easy"},{"id":"c03_q04","question":"What is the recommended ICS span of control?","options":["A. 1–2 direct reports","B. About 3–7 (optimally ~5)","C. 10–15","D. Unlimited"],"correct":1,"rationale":"One supervisor should directly manage roughly 3–7 people, classically 5. Larger spans trigger subdivision of the structure.","difficulty":"Easy"},{"id":"c03_q05","question":"A hazmat incident involves fire, police, EMS, and an environmental agency, each with legal authority. The best command arrangement is:","options":["A. Four separate command posts","B. Unified command — agencies share objectives under one plan with a single Operations section","C. Whoever arrived first commands alone forever","D. No command until the state arrives"],"correct":1,"rationale":"Unified command lets multiple jurisdictions/disciplines jointly command while preserving one coordinated plan — the fix for competing command posts.","difficulty":"Medium"},{"id":"c03_q06","question":"Which ICS role can immediately halt an unsafe operation?","options":["A. Public information officer","B. Safety officer","C. Finance chief","D. Staging manager"],"correct":1,"rationale":"The safety officer, part of the command staff, holds authority to stop any operation posing imminent danger.","difficulty":"Medium"},{"id":"c03_q07","question":"What is NIMS?","options":["A. A hospital bed-tracking software","B. The national doctrine standardizing incident management — ICS, resource typing, credentialing, mutual aid, EOCs","C. A triage algorithm","D. A federal response team"],"correct":1,"rationale":"NIMS standardizes how all agencies and levels of government manage incidents so systems interoperate — ICS is its on-scene management component.","difficulty":"Medium"},{"id":"c03_q08","question":"During a hospital disaster activation, a nurse receives conflicting instructions from her everyday manager and her assigned incident supervisor. Per ICS, she should:","options":["A. Follow her everyday manager","B. Follow her assigned incident supervisor — unity of command","C. Follow whichever instruction is easier","D. Do both"],"correct":1,"rationale":"ICS unity of command means each person reports to exactly one incident supervisor during the response, regardless of daily reporting lines.","difficulty":"Medium"},{"id":"c03_q09","question":"What must occur when command is transferred to a more senior officer?","options":["A. Nothing — it is automatic","B. A formal briefing of the incoming commander and an announcement to all","C. A written exam","D. Approval from the hospital CEO"],"correct":1,"rationale":"Command transfer requires a briefing (situation, resources, plan) and notification so every responder knows who now commands.","difficulty":"Medium"},{"id":"c03_q10","question":"The incident action plan is produced by which section?","options":["A. Planning","B. Operations","C. Logistics","D. Command staff only"],"correct":0,"rationale":"Planning collects information, tracks resources and the situation, and prepares the incident action plan for command approval.","difficulty":"Medium"},{"id":"c03_q11","question":"An Emergency Operations Center (EOC) primarily:","options":["A. Replaces the on-scene incident commander","B. Coordinates off-scene support — resources, information, and policy — for incident command","C. Performs field triage","D. Is only activated for federal disasters"],"correct":1,"rationale":"The EOC supports and coordinates from off-scene; it does not take over tactical command of the incident.","difficulty":"Hard"},{"id":"c03_q12","question":"In hospital incident command (e.g., HICS), a job action sheet is:","options":["A. A billing document","B. A role card defining the incident duties, reporting line, and tasks for an assigned position","C. A triage tag","D. A federal form"],"correct":1,"rationale":"Job action sheets translate the ICS structure into concrete role instructions so staff can step into incident positions quickly.","difficulty":"Medium"},{"id":"c03_q13","question":"A treatment group supervisor now directly manages 12 providers and is overwhelmed. The ICS-correct fix is:","options":["A. Work harder","B. Subdivide — create additional units/leaders to restore a 3–7 span of control","C. Remove the supervisor","D. Ignore it — span of control is advisory"],"correct":1,"rationale":"ICS is modular: when span of control exceeds ~7, the structure subdivides so every supervisor manages a workable number.","difficulty":"Medium"},{"id":"c03_q14","question":"Why does ICS insist on common terminology (plain language, no codes)?","options":["A. Tradition","B. So responders from different agencies understand each other without translation errors","C. To shorten radio traffic","D. To comply with billing rules"],"correct":1,"rationale":"Agencies have different internal codes; plain, common terminology prevents dangerous misunderstandings in multi-agency operations.","difficulty":"Easy"},{"id":"c03_q15","question":"Which statement about ICS scalability is TRUE?","options":["A. Every incident must activate all five sections fully","B. ICS expands and contracts modularly — small incidents may need only an incident commander","C. ICS applies only to incidents with over 100 casualties","D. Sections cannot be combined"],"correct":1,"rationale":"ICS is modular: functions are activated only as needed, growing with the incident and demobilizing as it resolves.","difficulty":"Easy"},{"id":"c03_q16","question":"A physician arrives at a hospital disaster and begins working wherever she sees need, without checking in. The ICS problem is:","options":["A. None — initiative is always good","B. No check-in means no accountability, no assigned supervisor, and broken resource tracking","C. Physicians are exempt from ICS","D. She should have gone to the EOC"],"correct":1,"rationale":"Check-in establishes accountability and puts responders into the structure with a defined role and supervisor; unassigned helpers are untracked and can be unsafe.","difficulty":"Hard"}]},"c04":{"chapter":"c04","questions":[{"id":"c04_q01","question":"What does SALT stand for?","options":["A. Safety, Airway, Lifting, Transport","B. Sort, Assess, Lifesaving interventions, Treatment and/or transport","C. Scene, Alert, Look, Treat","D. Stabilize, Assess, Load, Triage"],"correct":1,"rationale":"SALT — Sort, Assess, Lifesaving interventions, Treatment and/or transport — is the CDC-sponsored standardized mass-casualty triage method taught in BDLS.","difficulty":"Easy"},{"id":"c04_q02","question":"In the global sort, casualties who walk to the designated area are assessed:","options":["A. First","B. Second","C. Last","D. Never"],"correct":2,"rationale":"Walkers demonstrate perfusion, airway, and the ability to follow commands, so they receive the lowest individual-assessment priority — but they are still assessed.","difficulty":"Easy"},{"id":"c04_q03","question":"Which casualties are assessed FIRST after global sorting?","options":["A. Those who walked","B. Those who waved","C. Those who are still or have obvious life threats (e.g., massive bleeding)","D. Those who talk loudest"],"correct":2,"rationale":"Still casualties and those with obvious life threats have the highest probability of needing immediate lifesaving intervention, so they are assessed first.","difficulty":"Easy"},{"id":"c04_q04","question":"Which is a permitted lifesaving intervention DURING SALT triage?","options":["A. Splinting a femur fracture","B. Applying a tourniquet to massive extremity hemorrhage","C. Full spinal immobilization","D. Starting an IV infusion"],"correct":1,"rationale":"Triage-phase interventions take only seconds: hemorrhage control, airway positioning (child: consider 2 breaths), chest decompression, auto-injector antidotes. Splints, IVs, and immobilization wait for the treatment phase.","difficulty":"Medium"},{"id":"c04_q05","question":"An adult casualty is not breathing after you open the airway. In SALT, this casualty is categorized as:","options":["A. Immediate","B. Expectant","C. Dead","D. Delayed"],"correct":2,"rationale":"An apneic adult after airway opening is Dead (black) in mass-casualty triage; CPR for one arrest would consume resources needed by many salvageable casualties.","difficulty":"Medium"},{"id":"c04_q06","question":"How does SALT modify the apnea assessment for a child?","options":["A. No difference from adults","B. Consider giving 2 rescue breaths after opening the airway; if breathing does not resume, the child is Dead","C. Perform 10 minutes of CPR","D. All apneic children are Expectant"],"correct":1,"rationale":"Because pediatric arrest is usually hypoxic, SALT allows consideration of two rescue breaths for an apneic child — a seconds-long intervention that can restore breathing.","difficulty":"Medium"},{"id":"c04_q07","question":"A breathing casualty obeys commands, has a radial pulse, no respiratory distress, controlled bleeding, and only abrasions. Category?","options":["A. Immediate","B. Delayed","C. Minimal","D. Expectant"],"correct":2,"rationale":"All assessment questions are 'yes' and the injuries are minor — Minimal (green).","difficulty":"Easy"},{"id":"c04_q08","question":"A breathing casualty obeys commands, has a pulse, no distress, controlled hemorrhage — but has an obviously fractured femur. Category?","options":["A. Minimal","B. Delayed","C. Immediate","D. Dead"],"correct":1,"rationale":"All questions 'yes' with significant (but not immediately life-threatening) injuries = Delayed (yellow).","difficulty":"Medium"},{"id":"c04_q09","question":"A casualty is breathing but does not obey commands and has no radial pulse. Resources are adequate for prompt care. Category?","options":["A. Minimal","B. Delayed","C. Immediate","D. Expectant"],"correct":2,"rationale":"Any 'no' answer with a reasonable chance of survival given current resources = Immediate (red) — top priority for treatment and transport.","difficulty":"Medium"},{"id":"c04_q10","question":"What does the Expectant (gray) category signify?","options":["A. The casualty is deceased","B. Alive, but survival unlikely with currently available resources; provide comfort care and re-triage if resources improve","C. The casualty refused care","D. Minor injuries only"],"correct":1,"rationale":"Expectant is a resource-driven category, not abandonment: comfort care is given, and the patient is upgraded if the resource picture changes.","difficulty":"Easy"},{"id":"c04_q11","question":"Why is mass-casualty triage repeated at multiple stages (re-triage)?","options":["A. Regulatory paperwork","B. Because patients deteriorate or improve and resources change over time","C. To keep responders busy","D. It is not repeated"],"correct":1,"rationale":"Triage is a snapshot with incomplete data. Re-triage at the treatment area, before transport, and at hospital arrival catches deterioration and allows upgrades.","difficulty":"Easy"},{"id":"c04_q12","question":"The fundamental goal of mass-casualty triage is to:","options":["A. Give every patient maximal individual care","B. Produce the greatest number of survivors with the available resources","C. Transport patients in order of arrival","D. Identify patients for research"],"correct":1,"rationale":"Triage rations limited resources to maximize total survival — a deliberate departure from everyday maximal individual care.","difficulty":"Easy"},{"id":"c04_q13","question":"A triage officer stops to splint fractures and bandage minor wounds during the assessment pass. The problem is:","options":["A. None — treatment is always good","B. Triage halts for everyone not yet sorted; only seconds-long lifesaving interventions belong in the triage pass","C. Splinting requires physician orders","D. Bandaging is a logistics function"],"correct":1,"rationale":"The triage officer's job is sorting the whole scene. Prolonged care during triage leaves unsorted casualties — possibly Immediate ones — undiscovered.","difficulty":"Medium"},{"id":"c04_q14","question":"Which casualty is at greatest risk of being mishandled by an untrained crowd-driven response?","options":["A. The loudly screaming walking wounded","B. The silent, still casualty who cannot call for help","C. The casualty with a minor laceration","D. The bystander"],"correct":1,"rationale":"Noise attracts attention, but the still and silent are often the most critical — which is why SALT assesses them first.","difficulty":"Medium"},{"id":"c04_q15","question":"More ambulances and a second trauma team arrive. What should happen to Expectant-category patients?","options":["A. Nothing — categories are final","B. Re-triage them; with more resources some may now be Immediate","C. Move them to the morgue","D. Discharge them"],"correct":1,"rationale":"Expectant is defined relative to available resources. When resources improve, re-triage can and should upgrade salvageable patients.","difficulty":"Hard"},{"id":"c04_q16","question":"A casualty walked to the green area, but 20 minutes later is pale, tachycardic, and confused. What does this demonstrate?","options":["A. Walking wounded never deteriorate","B. The need for ongoing assessment and re-triage — green patients can harbor evolving internal injuries","C. The initial sort was illegal","D. The patient should be moved to Dead"],"correct":1,"rationale":"The global sort is a first pass, not a clearance. Occult injuries (e.g., internal hemorrhage) evolve — monitoring and re-triage of the green area is mandatory.","difficulty":"Hard"},{"id":"c04_q17","question":"Auto-injector antidotes given during the SALT lifesaving-intervention step are most relevant to which event type?","options":["A. Earthquake","B. Nerve-agent / organophosphate chemical exposure","C. Flood","D. Heat wave"],"correct":1,"rationale":"Antidote auto-injectors (e.g., for nerve agents) are seconds-long, potentially lifesaving triage interventions in chemical events.","difficulty":"Medium"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"Small Town, Big Bus Crash","presentation":"A bus crash outside a small rural town produces 22 injured passengers. The local critical-access hospital has one physician on duty, four nurses, and two ambulances. The nearest trauma center is 90 minutes away.","vitals":{"patients":"22 injured","staff":"1 MD, 4 RNs","transport":"2 ambulances"},"question":"How should this event be classified and managed?","options":["A: A routine emergency — treat patients in order of arrival.","B: A disaster/MCI for this community — needs exceed local resources, so activate the emergency plan, use formal triage, and request mutual aid.","C: Not a disaster because there are fewer than 100 casualties.","D: Wait for a federal declaration before changing procedures."],"correct":1,"explanation":"Twenty-two casualties overwhelm one physician, four nurses, and two ambulances — needs exceed resources, which is the definition of a disaster regardless of absolute numbers. The correct posture is plan activation, triage for the greatest good, and early mutual-aid requests.","clinicalPearl":"Disaster is a local arithmetic problem: the same crash near a level-1 trauma center might be just a busy afternoon."},{"id":"c01_s02","title":"The Plan on the Shelf","presentation":"During accreditation review, a hospital presents a comprehensive 200-page disaster plan. Interviews reveal no staff member has participated in a drill for three years, and the plan's phone tree lists departed employees.","vitals":{"plan":"Comprehensive on paper","exercises":"None in 3 years","contacts":"Outdated"},"question":"What is the most important corrective action?","options":["A: Add more chapters to the plan.","B: Exercise the plan regularly, update contacts, and train staff — planning and practice are inseparable.","C: Nothing — a written plan satisfies preparedness.","D: Replace the plan with verbal instructions."],"correct":1,"explanation":"The PRE-DISASTER Paradigm pairs planning with practice. An unexercised, outdated plan fails under stress; drills reveal gaps (like the dead phone tree) and build the role familiarity a real response requires.","clinicalPearl":"A disaster plan is only as good as its last exercise."},{"id":"c01_s03","title":"The Responder Who Couldn't Respond","presentation":"After an earthquake, a hospital activates its surge plan, but a third of the staff do not report: schools are closed, roads are damaged, and many have no family emergency arrangements. Care capacity collapses despite an intact building.","vitals":{"building":"Intact","staff reporting":"~66%","surge plan":"Activated"},"question":"What preparedness lesson does this illustrate?","options":["A: Surge capacity is only about beds and supplies.","B: Staff personal and family preparedness is a core component of facility surge capacity.","C: Staff who stay home should be dismissed.","D: The surge plan was unnecessary."],"correct":1,"explanation":"Surge capacity = space, supplies, systems, AND staff. Employees without family communication plans, dependent-care arrangements, and go-kits often cannot report, so facility preparedness programs must include personal preparedness.","clinicalPearl":"Beds don't treat patients — people do. Personal preparedness is institutional capacity."}]},"c02":{"chapter":"c02","cases":[{"id":"c02_s01","title":"First on Scene at the Market Explosion","presentation":"You are the first EMS unit at an explosion in a crowded market. Smoke is rising, dozens of people are down or fleeing, and bystanders scream for you to help a bleeding man at your feet.","vitals":{"casualties":"Est. 30+","hazards":"Smoke, unstable stalls, possible 2nd device","resources":"Your unit only"},"question":"What is your correct first sequence of actions?","options":["A: Immediately treat the bleeding man in front of you.","B: Size up and report (detection), establish and announce incident command, address safety/security and hazards — before individual patient care.","C: Drive the nearest casualty to the hospital.","D: Wait outside the area until the police arrive."],"correct":1,"explanation":"The DISASTER Paradigm runs in order: detection (size-up and report), incident command, safety/security, and hazard assessment come before touching the first patient. At a bombing, secondary devices make staging discipline and scene control lifesaving for responders — and effective command saves more victims than one-at-a-time care.","clinicalPearl":"The hardest BDLS skill is stepping past the first casualty to run the checklist — command and safety save more lives than immediate hands-on care."},{"id":"c02_s02","title":"Everyone to Mercy General","presentation":"At a highway pile-up MCI with 25 casualties, transporting crews begin taking every patient to Mercy General, 5 minutes away. Two other hospitals, 15 and 20 minutes away, have received no patients. Mercy's ED calls: they are saturated.","vitals":{"casualties":"25","nearest ED":"Saturated","other EDs":"Idle"},"question":"What has gone wrong, and what should command do?","options":["A: Nothing — nearest hospital is always correct.","B: Evacuation failed: casualties were not distributed. Command should assign destinations by acuity across all appropriate receiving facilities.","C: Mercy General should simply work faster.","D: Stop all transports until Mercy clears."],"correct":1,"explanation":"Sending every casualty to the closest facility relocates the disaster into its ED. The evacuation component requires command-directed distribution: match patient acuity to facility capability and spread the load across the system.","clinicalPearl":"An MCI transported badly becomes a hospital MCI — distribution is a command function, not a driver's choice."},{"id":"c02_s03","title":"The Second Wave","presentation":"Twenty minutes into a response at an industrial fire, crews have settled into patient care. A responder notices a storage tank near the treatment area beginning to vent vapor. The initial hazard assessment had cleared this area.","vitals":{"scene":"Evolving","new hazard":"Venting tank near treatment area","initial assessment":"20 min old"},"question":"What does this development demonstrate?","options":["A: The initial assessment was negligent.","B: Hazard assessment is continuous — scenes evolve, so the treatment area must be relocated and command notified immediately.","C: Vapor clouds are harmless once patients are triaged.","D: Only the safety officer may notice hazards."],"correct":1,"explanation":"The 'Assess hazards' component never ends: an area safe on arrival can become dangerous. Any responder who spots a new hazard reports it at once; command relocates operations and updates the safety perimeter.","clinicalPearl":"Your scene size-up has an expiration time — keep looking up from the patient."}]},"c03":{"chapter":"c03","cases":[{"id":"c03_s01","title":"Two Command Posts","presentation":"At a train derailment with a chemical leak, the fire department has set up a command post on the east side while police run a separate post on the west side. EMS crews receive conflicting orders about staging locations.","vitals":{"agencies":"Fire, Police, EMS, Environmental","command posts":"2 (conflicting)","orders":"Contradictory"},"question":"What is the correct structural fix?","options":["A: Let each agency keep its own command post.","B: Establish unified command — the agencies jointly set objectives at one command post with a single coordinated plan and one Operations section.","C: EMS should create a third command post.","D: Wait for a federal coordinator."],"correct":1,"explanation":"Multi-jurisdiction, multi-discipline incidents call for unified command: shared decision-making, one incident action plan, one Operations section. Parallel command posts guarantee conflicting orders and gaps.","clinicalPearl":"One incident, one plan — unified command merges authority without merging agencies."},{"id":"c03_s02","title":"The Overloaded Supervisor","presentation":"In the hospital's disaster response, the treatment area leader is directly supervising 14 clinicians. Requests are being missed, two patients were nearly given duplicate medications, and the leader cannot say who is assigned where.","vitals":{"direct reports":"14","errors":"Near-misses occurring","tracking":"Lost"},"question":"What ICS principle is violated and what is the fix?","options":["A: Nothing is wrong; busy leaders are normal in disasters.","B: Span of control is broken — subdivide into units of ~5 with unit leaders reporting to the treatment leader.","C: Replace the leader with two co-equal leaders over the same 14 people.","D: Send half the staff home."],"correct":1,"explanation":"Span of control should stay around 3–7 direct reports. The modular fix is subdividing: create unit leaders, each managing a workable group, restoring accountability and safe communication.","clinicalPearl":"When a leader can't name their people, the span has already failed — subdivide before the error happens."},{"id":"c03_s03","title":"Where Do I Go?","presentation":"A hospital activates its incident command for a mass-casualty event. An off-duty nurse hears the news and drives straight to the ED, walking into the treatment area to help without telling anyone.","vitals":{"activation":"HICS active","nurse status":"Not checked in","assignment":"None"},"question":"What should the nurse have done?","options":["A: Exactly what she did — every hand helps.","B: Report to the designated staff check-in/labor pool, receive an assignment and job action sheet, and work under an assigned supervisor.","C: Call the CEO for instructions.","D: Stay home under all circumstances."],"correct":1,"explanation":"Willing staff are valuable only when integrated: check-in establishes accountability, matches skills to needs via job action sheets, and places the responder under one incident supervisor. Untracked helpers break safety and resource management.","clinicalPearl":"In a disaster, checking in IS helping — the labor pool is where good intentions become usable capacity."}]},"c04":{"chapter":"c04","cases":[{"id":"c04_s01","title":"Thirty Down at the Stadium","presentation":"A structural collapse at a stadium exit leaves roughly 30 casualties. You are the designated triage officer. Some victims are screaming, several lie motionless, and dozens of others mill around dazed.","vitals":{"casualties":"~30","your role":"Triage officer","resources":"First units arriving"},"question":"What is your first triage action?","options":["A: Begin detailed head-to-toe exams on the nearest patient.","B: Global sort by voice: ask those who can to walk to a designated area, then ask the rest to wave — assessing the still and obviously bleeding first.","C: Start CPR on the first pulseless casualty.","D: Transport the loudest patient first."],"correct":1,"explanation":"SALT starts with global sorting: walkers are prioritized last, wavers second, and the still or obviously hemorrhaging first. This sorts 30 casualties in seconds and directs individual assessment where it matters most.","clinicalPearl":"Let your voice triage the crowd before your hands triage a patient."},{"id":"c04_s02","title":"The Apneic Adult and the Apneic Child","presentation":"During your assessment pass you find two apneic casualties near each other: a middle-aged man and a 6-year-old girl. You open each airway with positioning. The man remains apneic. After the girl's airway is opened you consider further action.","vitals":{"man":"Apneic after airway opening","child":"Apneic, airway just opened","scene":"Active MCI, resources scarce"},"question":"Per SALT, what is correct?","options":["A: Start CPR on both.","B: The man is Dead (black); for the child, consider two rescue breaths — if breathing resumes she is triaged as living (likely Immediate); if not, she is Dead.","C: Both are Expectant.","D: Tag both Immediate and move on."],"correct":1,"explanation":"In mass-casualty triage, an apneic adult after airway opening is Dead — CPR would consume many rescuers for one arrest. Children get consideration of two rescue breaths because pediatric arrest is typically hypoxic and may reverse with ventilation alone.","clinicalPearl":"SALT's only 'CPR' is two breaths for a child — the highest-yield seconds in pediatric triage."},{"id":"c04_s03","title":"Gray, Not Black","presentation":"A casualty has an open skull injury with exposed brain tissue, agonal-pattern breathing, and no radial pulse. Your only transport is 40 minutes out, and three Immediate patients await treatment. Later, two helicopters and a surgical team arrive.","vitals":{"initial resources":"Minimal","later resources":"2 helicopters + surgical team","patient":"Breathing, catastrophic head injury"},"question":"How is this casualty triaged initially, and what happens when resources improve?","options":["A: Dead initially and finally.","B: Expectant (gray) initially — comfort care, not abandonment; on resource arrival, re-triage and potentially upgrade to Immediate.","C: Immediate initially, Expectant later.","D: Minimal — he is breathing."],"correct":1,"explanation":"Survival is unlikely with the resources initially available, so the casualty is Expectant with comfort care. Expectant is resource-relative: when helicopters and a surgical team arrive, re-triage may upgrade the patient to Immediate.","clinicalPearl":"Expectant is a statement about your resources, not a verdict on the patient — re-triage when the math changes."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"The Disaster Cycle — Health Professional's Role by Phase","description":"The four continuous phases of emergency management and what health professionals contribute in each.","steps":["Mitigation: support measures that reduce future impact — safe facilities, building codes, immunization, community risk reduction.","Preparedness: write and exercise plans, train (BDLS/ADLS), stockpile, prepare yourself and your family.","Response: operate inside incident command using the DISASTER Paradigm — triage, treat, and protect yourself and the scene.","Recovery: restore services, support community and responder mental health, capture lessons learned.","Feed lessons learned back into mitigation and planning — the cycle never ends."]},{"id":"c01_alg02","title":"PRE-DISASTER Readiness Sequence","description":"Pre-event readiness per the PRE-DISASTER Paradigm, from the individual to the community level.","steps":["Plan: personal/family plan, facility plan, community plan — with clear roles.","Practice: drill and exercise the plans; update contacts and supplies after every exercise.","Build resilience: hardened infrastructure, redundant systems, healthy and prepared people.","Educate and train: competency-based courses so all responders share one lexicon.","Re-assess hazards and repeat — readiness decays without maintenance."]}]},"c02":{"chapter":"c02","algorithms":[{"id":"c02_alg01","title":"The DISASTER Paradigm — Response Checklist","description":"The eight ordered components applied by the first-arriving and every subsequent responder at any all-hazards event.","steps":["Detection: size up — do needs exceed resources? Report casualties, hazards, and needs; declare an MCI/disaster if so.","Incident command: the first trained responder establishes and announces command; transfer as senior officers arrive.","Safety and security: protect in order — self, team, public, patients; PPE, staging, perimeter, resource security.","Assess hazards: search for ongoing and secondary hazards (fire, collapse, hazmat, devices); reassess continuously.","Support: request staff, supplies, transport, and special teams early — anticipate the incident an hour ahead.","Triage and treatment: apply SALT; deliver the greatest good for the greatest number.","Evacuation: move the right patient to the right destination; distribute across receiving facilities.","Recovery: begin during response — restore systems, support people, capture lessons learned."]}]},"c03":{"chapter":"c03","algorithms":[{"id":"c03_alg01","title":"Standing Up Incident Command","description":"From first arrival to a fully functioning command structure.","steps":["First trained responder establishes command and announces it on the designated channel.","Perform initial size-up and transmit the detection report.","Appoint command staff as needed: safety officer first, then public information and liaison officers.","Activate functional sections modularly as workload requires: Operations first, then Planning, Logistics, Finance/Administration.","Maintain span of control (~3–7 per supervisor); subdivide with branches/divisions/groups as the incident grows.","Use unified command when multiple jurisdictions/disciplines hold authority.","Transfer command formally with a briefing and announcement when a more qualified/designated officer arrives.","Demobilize modularly as the incident resolves; document through Planning and Finance."]},{"id":"c03_alg02","title":"Health Professional Check-In Flow (Hospital ICS)","description":"How clinical staff enter and work inside the hospital incident command structure.","steps":["On activation, report to the designated check-in point / labor pool — never self-assign.","Receive your incident role and job action sheet.","Identify your single incident supervisor and your reporting channel.","Perform assigned tasks; escalate resource needs and hazards up the chain.","Decline tasks outside your competence and say so — reassignment is a safety function.","At relief or shift end: give a formal handoff and demobilize through the system."]}]},"c04":{"chapter":"c04","algorithms":[{"id":"c04_alg01","title":"SALT Mass-Casualty Triage","description":"The CDC-sponsored national standard triage flow, from global sorting through category assignment.","steps":["STEP 1 — Sort globally: 'If you can hear me and need help, walk to this area' (assess these third). 'Wave your arm or move' (assess these second). Still casualties or obvious life threats: assess FIRST.","STEP 2 — Assess each casualty individually, performing lifesaving interventions that take only seconds:","Control massive hemorrhage (tourniquet/direct pressure).","Open the airway by positioning; for a child, consider 2 rescue breaths.","Needle decompression for tension pneumothorax (trained providers).","Auto-injector antidotes if chemical exposure indicated.","Not breathing after airway opening (adult, or child after breaths) → DEAD (black).","Breathing: ask — obeys commands/purposeful movement? peripheral pulse? no respiratory distress? major hemorrhage controlled?","All YES + minor injuries → MINIMAL (green). All YES + significant injuries → DELAYED (yellow).","Any NO + survivable with current resources → IMMEDIATE (red). Any NO + survival unlikely with current resources → EXPECTANT (gray, comfort care).","Tag/mark, move to the next casualty, and RE-TRIAGE at the treatment area, before transport, and on arrival."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"The Four Phases of the Disaster Cycle","headers":["Phase","When","Examples"],"rows":[["Mitigation","Before (ongoing)","Building codes, flood barriers, immunization programs"],["Preparedness","Before","Plans, drills, training, stockpiles, family go-kits"],["Response","During / immediately after","Incident command, triage, treatment, evacuation"],["Recovery","After (weeks to years)","Restoring services, rebuilding, mental-health support, lessons learned"]]},{"id":"c01_t02","title":"Everyday Emergency Care vs Disaster Care","headers":["Aspect","Everyday Care","Disaster Care"],"rows":[["Goal","Maximal care for each patient","Greatest good for the greatest number"],["Resources","Assumed adequate","Explicitly limited; allocated by triage"],["Documentation","Complete records","Abbreviated (triage tags)"],["Roles","Fixed daily roles","Flexible, assigned by incident command"],["Care standard","Conventional","May shift to contingency or crisis standards"]]}]},"c02":{"chapter":"c02","tables":[{"id":"c02_t01","title":"The DISASTER Paradigm at a Glance","headers":["Component","Core Question","Key Actions"],"rows":[["Detection","Do needs exceed resources?","Size up, estimate casualties/hazards, report, declare MCI"],["Incident command","Who is in charge?","Establish, announce, transfer as needed"],["Safety & security","Who must be protected first?","Self → team → public → patients; PPE; perimeter"],["Assess hazards","What can still hurt us?","Ongoing + secondary hazards; continuous reassessment"],["Support","What will we need?","Early requests: staff, supplies, transport, special teams"],["Triage & treatment","Who first, with what?","SALT; greatest good for greatest number"],["Evacuation","Who goes where?","Acuity-matched, distributed destinations"],["Recovery","How do we restore?","Begins during response; systems, people, lessons"]]},{"id":"c02_t02","title":"Obvious vs Insidious Detection","headers":["Feature","Obvious Event","Insidious Event"],"rows":[["Example","Explosion, tornado","Covert biological release, epidemic"],["Signal","Immediate scene chaos","Syndromic clusters across EDs over days"],["Detector","First responders on scene","Clinicians + public-health surveillance"],["Key action","Size-up and MCI declaration","Recognize pattern, notify public health"]]}]},"c03":{"chapter":"c03","tables":[{"id":"c03_t01","title":"The Five ICS Functional Sections","headers":["Section","One-Line Job","Health Examples"],"rows":[["Command","Sets objectives; overall authority (+ safety, PIO, liaison)","Declares surge levels; approves the plan"],["Operations","Does the tactical work","Triage, treatment, transport, decon"],["Planning","Tracks situation/resources; writes the action plan","Bed counts, patient tracking, next operational period"],["Logistics","Gets what the response needs","Ventilators, staff food, radios, supplies"],["Finance/Admin","Tracks costs, claims, time","Emergency procurement, staff hours, reimbursement"]]},{"id":"c03_t02","title":"ICS Core Principles","headers":["Principle","Meaning"],"rows":[["Common terminology","Plain language, no agency codes"],["Modular organization","Activate only what the incident needs; expand/contract"],["Unity of command","Every person reports to exactly one incident supervisor"],["Span of control","~3–7 direct reports per supervisor (optimally ~5)"],["Unified command","Multi-agency incidents share objectives under one plan"],["Accountability","Check-in, assignment, tracking, formal handoffs"]]}]},"c04":{"chapter":"c04","tables":[{"id":"c04_t01","title":"SALT Triage Categories","headers":["Category","Color","Meaning","Action"],"rows":[["Immediate","Red","Life threat, survivable with prompt care","First priority treatment and transport"],["Delayed","Yellow","Significant injuries; care can wait","Treat/transport after Immediate"],["Minimal","Green","Walking wounded, minor injuries","Assess, treat minor issues, monitor for deterioration"],["Expectant","Gray","Alive; survival unlikely with CURRENT resources","Comfort care; re-triage if resources improve"],["Dead","Black","Not breathing after airway opening","No further care; preserve scene/identification"]]},{"id":"c04_t02","title":"SALT Global Sort Priorities","headers":["Response to Commands","Assessment Priority"],"rows":[["Still / obvious life threat","1st — assess first"],["Waves / purposeful movement","2nd"],["Walks to designated area","3rd (last) — still gets assessed"]]},{"id":"c04_t03","title":"Triage-Phase Lifesaving Interventions (Seconds Only)","headers":["Intervention","Indication"],"rows":[["Tourniquet / direct pressure","Massive external hemorrhage"],["Airway positioning","Obstructed airway in an unresponsive casualty"],["2 rescue breaths (child only)","Apneic child after airway opening"],["Needle chest decompression (trained)","Suspected tension pneumothorax"],["Antidote auto-injector","Nerve-agent/organophosphate toxidrome"]]}]}}};
